// src/pages/dashboard/AdminDashboard.js
import React from "react";
import Layout from "../../components/layout/Layout";
import { Bar } from "react-chartjs-2";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Title,
  Tooltip,
  Legend,
} from "chart.js";

ChartJS.register(CategoryScale, LinearScale, BarElement, Title, Tooltip, Legend);

function AdminDashboard() {
  const chartData = {
    labels: ["Jan", "Feb", "Mar", "Apr", "May", "Jun"],
    datasets: [
      {
        label: "New Users",
        data: [120, 190, 300, 250, 400, 350],
        backgroundColor: "#4f46e5",
        borderRadius: 6,
      },
      {
        label: "Courses Published",
        data: [20, 25, 18, 30, 28, 40],
        backgroundColor: "#10b981",
        borderRadius: 6,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: { position: "top" },
      title: { display: false },
    },
  };

  return (
    <Layout pageTitle="Admin Dashboard">
      
      <h2 style={{ fontWeight: "700", marginBottom: "30px" }}>
        Admin Overview
      </h2>

      {/* STAT CARDS */}
      <div className="row g-4 mb-4">
        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Total Users</h6>
            <h2 className="fw-bold">1,234</h2>
            <span className="text-success">+5.4% since last month</span>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Courses Published</h6>
            <h2 className="fw-bold">56</h2>
            <span className="text-success">+2 new courses</span>
          </div>
        </div>

        <div className="col-md-4">
          <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
            <h6 className="text-muted">Pending Approvals</h6>
            <h2 className="fw-bold">7</h2>
            <span className="text-warning">Needs attention</span>
          </div>
        </div>
      </div>

      {/* CHART */}
      <div className="card shadow-sm p-4 mb-4" style={{ borderRadius: "12px" }}>
        <h5 className="mb-4 fw-semibold">Monthly Activity</h5>
        <Bar data={chartData} options={chartOptions} />
      </div>

      {/* RECENT ACTIVITY */}
      <div className="card shadow-sm p-4" style={{ borderRadius: "12px" }}>
        <h5 className="mb-4 fw-semibold">Recent Activity</h5>

        <ul className="list-group list-group-flush">
          <li className="list-group-item d-flex justify-content-between">
            New course "React Basics" submitted
            <span className="text-muted">2h ago</span>
          </li>
          <li className="list-group-item d-flex justify-content-between">
            User Jane Smith registered
            <span className="text-muted">5h ago</span>
          </li>
          <li className="list-group-item d-flex justify-content-between">
            Course "Advanced Python" approved
            <span className="text-muted">1d ago</span>
          </li>
        </ul>
      </div>

    </Layout>
  );
}

export default AdminDashboard;
